# URL/command patterns that indicate a well-known tool being installed
# Format: url_pattern<TAB>tool_name<TAB>pkg_path
# Matched as substring against the full RUN body (before && splitting)

nodejs.org/dist	nodejs	nodejs
deb.nodesource.com	nodejs	nodejs
raw.githubusercontent.com/nvm-sh/nvm	nvm	nodejs
