python-poetry.org	poetry	poetry
rustup.rs	rustup	rustc
sh.rustup.rs	rustup	rustc
get.docker.com	docker	docker-client
dl.google.com/go	golang	go
golang.org/dl	golang	go
get.helm.sh	helm	kubernetes-helm
raw.githubusercontent.com/helm	helm	kubernetes-helm
starship.rs/install.sh	starship	starship
mise.jdx.dev	mise	mise
